import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import {
  Plus,
  FileText,
  BarChart3,
  Settings,
  Copy,
  Trash2,
  Eye,
  Download,
  Share2
} from 'lucide-react';
import axios from 'axios';
import toast from 'react-hot-toast';

const Surveys = () => {
  const { user } = useAuth();
  const [surveys, setSurveys] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchSurveys();
  }, []);

  const fetchSurveys = async () => {
    try {
      const response = await axios.get('/api/surveys');
      setSurveys(response.data);
    } catch (error) {
      console.error('Error fetching surveys:', error);
      toast.error('Failed to load surveys');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this survey?')) {
      try {
        await axios.delete(`/api/surveys/${id}`);
        toast.success('Survey deleted successfully');
        fetchSurveys();
      } catch (error) {
        console.error('Error deleting survey:', error);
        toast.error('Failed to delete survey');
      }
    }
  };

  const handleCopy = async (id) => {
    try {
      await axios.post(`/api/surveys/${id}/copy`);
      toast.success('Survey copied successfully');
      fetchSurveys();
    } catch (error) {
      console.error('Error copying survey:', error);
      toast.error('Failed to copy survey');
    }
  };

  const handleExport = async (id) => {
    try {
      const response = await axios.get(`/api/responses/export/${id}`, {
        responseType: 'blob'
      });

      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `survey-${id}-responses.csv`);
      document.body.appendChild(link);
      link.click();
      link.remove();

      toast.success('Responses exported successfully');
    } catch (error) {
      console.error('Error exporting responses:', error);
      toast.error('Failed to export responses');
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="spinner w-8 h-8"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">My Surveys</h1>
          <p className="text-gray-600">Manage and track your surveys</p>
        </div>
        <Link
          to="/builder"
          className="btn-primary"
        >
          <Plus className="h-4 w-4 mr-2" />
          Create Survey
        </Link>
      </div>

      {/* Surveys Grid */}
      {surveys.length === 0 ? (
        <div className="text-center py-12">
          <FileText className="h-12 w-12 text-gray-400 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-gray-900 mb-2">No surveys yet</h3>
          <p className="text-gray-600 mb-6">Create your first survey to get started</p>
          <Link
            to="/builder"
            className="btn-primary"
          >
            <Plus className="h-4 w-4 mr-2" />
            Create Your First Survey
          </Link>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {surveys.map((survey) => (
            <div key={survey.id} className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
              <div className="flex justify-between items-start mb-4">
                <div className="flex-1">
                  <h3 className="text-lg font-semibold text-gray-900 mb-1">
                    {survey.title}
                  </h3>
                  {survey.description && (
                    <p className="text-sm text-gray-600 line-clamp-2">
                      {survey.description}
                    </p>
                  )}
                </div>
                <div className="flex items-center space-x-1">
                  <span className={`px-2 py-1 text-xs font-medium rounded-full ${
                    survey.status === 'published' 
                      ? 'bg-green-100 text-green-800'
                      : 'bg-yellow-100 text-yellow-800'
                  }`}>
                    {survey.status}
                  </span>
                </div>
              </div>

              <div className="flex items-center justify-between text-sm text-gray-500 mb-4">
                <span>{survey.questions?.length || 0} questions</span>
                <span>{survey.responses_count || 0} responses</span>
              </div>

              <div className="flex items-center justify-between">
                <div className="flex space-x-2">
                  <Link
                    to={`/preview/${survey.id}`}
                    className="p-2 text-gray-400 hover:text-gray-600 transition-colors"
                    title="Preview"
                  >
                    <Eye className="h-4 w-4" />
                  </Link>
                  <Link
                    to={`/analytics/${survey.id}`}
                    className="p-2 text-gray-400 hover:text-gray-600 transition-colors"
                    title="Analytics"
                  >
                    <BarChart3 className="h-4 w-4" />
                  </Link>
                  <button
                    onClick={() => handleExport(survey.id)}
                    className="p-2 text-gray-400 hover:text-gray-600 transition-colors"
                    title="Export Responses"
                  >
                    <Download className="h-4 w-4" />
                  </button>
                </div>
                <div className="flex space-x-2">
                  <Link
                    to={`/builder/${survey.id}`}
                    className="p-2 text-gray-400 hover:text-gray-600 transition-colors"
                    title="Edit"
                  >
                    <Settings className="h-4 w-4" />
                  </Link>
                  <button
                    onClick={() => handleCopy(survey.id)}
                    className="p-2 text-gray-400 hover:text-gray-600 transition-colors"
                    title="Copy"
                  >
                    <Copy className="h-4 w-4" />
                  </button>
                  <button
                    onClick={() => handleDelete(survey.id)}
                    className="p-2 text-red-400 hover:text-red-600 transition-colors"
                    title="Delete"
                  >
                    <Trash2 className="h-4 w-4" />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Surveys;
